import React, { useState, useEffect } from 'react';
import { addressAPI, ordersAPI, getUserIdFromToken, getMongoId } from '../api/api';
//import './CheckoutPage.css';

const CheckoutPage = ({ 
    cart, 
    user, 
    setCurrentPage, 
    setError, 
    setLoading,
    clearCart 
}) => {
    const [addresses, setAddresses] = useState([]);
    const [selectedAddress, setSelectedAddress] = useState(null);
    const [showAddressForm, setShowAddressForm] = useState(false);
    const [orderPlaced, setOrderPlaced] = useState(false);
    const [orderNumber, setOrderNumber] = useState('');
    const [newAddress, setNewAddress] = useState({
        fullName: user?.fullName || '',
        email: user?.email || '',
        mobile: user?.mobile || '',
        addressLine1: '',
        addressLine2: '',
        city: '',
        state: '',
        zipCode: '',
        country: 'India',
        isDefault: false
    });

    useEffect(() => {
        loadAddresses();
    }, []);

    const loadAddresses = async () => {
        try {
            setLoading(true);
            const response = await addressAPI.getAll();
            const addrs = response.data || [];
            setAddresses(addrs);
            const defaultAddr = addrs.find(a => a.isDefault);
            if (defaultAddr) setSelectedAddress(getMongoId(defaultAddr));
        } catch (err) {
            console.error('Error loading addresses:', err);
            setError('Failed to load addresses');
        } finally {
            setLoading(false);
        }
    };

    const handleAddAddress = async (e) => {
        e.preventDefault();
        try {
            setLoading(true);
            await addressAPI.add(newAddress);
            setNewAddress({
                fullName: user?.fullName || '',
                email: user?.email || '',
                mobile: user?.mobile || '',
                addressLine1: '',
                addressLine2: '',
                city: '',
                state: '',
                zipCode: '',
                country: 'India',
                isDefault: false
            });
            setShowAddressForm(false);
            await loadAddresses();
        } catch (err) {
            console.error('Error adding address:', err);
            setError('Failed to add address');
        } finally {
            setLoading(false);
        }
    };

    const handlePlaceOrder = async () => {
        if (!selectedAddress) {
            setError('Please select a delivery address');
            return;
        }

        try {
            setLoading(true);
            const response = await ordersAPI.confirm(selectedAddress);
            setOrderPlaced(true);
            setOrderNumber(response.data?.orderNumber || response.data?._id);
            clearCart();
            setTimeout(() => {
                setCurrentPage('orders');
            }, 3000);
        } catch (err) {
            console.error('Error placing order:', err);
            setError(err.response?.data?.message || 'Failed to place order');
        } finally {
            setLoading(false);
        }
    };

    const cartTotal = cart?.reduce((sum, item) => sum + (item.price * item.quantity), 0) || 0;
    const shipping = cartTotal > 500 ? 0 : 50;
    const tax = cartTotal * 0.18;
    const grandTotal = cartTotal + shipping + tax;

    if (orderPlaced) {
        return (
            <div className="checkout-container success-page">
                <div className="success-card">
                    <div className="success-icon">✓</div>
                    <h2>Order Placed Successfully!</h2>
                    <p className="order-number">Order #: {orderNumber}</p>
                    <p>You will be redirected to your orders page shortly...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="checkout-container">
            <div className="checkout-wrapper">
                {/* Left Section - Delivery & Payment */}
                <div className="checkout-left">
                    {/* Delivery Section */}
                    <div className="checkout-section">
                        <div className="section-header">
                            <h2>1. Delivery Address</h2>
                            <button 
                                className="btn-add-address"
                                onClick={() => setShowAddressForm(!showAddressForm)}
                            >
                                + Add New Address
                            </button>
                        </div>

                        {showAddressForm && (
                            <form className="address-form" onSubmit={handleAddAddress}>
                                <div className="form-row">
                                    <input
                                        type="text"
                                        placeholder="Full Name"
                                        value={newAddress.fullName}
                                        onChange={(e) => setNewAddress({...newAddress, fullName: e.target.value})}
                                        required
                                    />
                                    <input
                                        type="email"
                                        placeholder="Email"
                                        value={newAddress.email}
                                        onChange={(e) => setNewAddress({...newAddress, email: e.target.value})}
                                        required
                                    />
                                </div>
                                <div className="form-row">
                                    <input
                                        type="tel"
                                        placeholder="Mobile Number"
                                        value={newAddress.mobile}
                                        onChange={(e) => setNewAddress({...newAddress, mobile: e.target.value})}
                                        required
                                    />
                                    <input
                                        type="text"
                                        placeholder="Zip Code"
                                        value={newAddress.zipCode}
                                        onChange={(e) => setNewAddress({...newAddress, zipCode: e.target.value})}
                                        required
                                    />
                                </div>
                                <input
                                    type="text"
                                    placeholder="Address Line 1"
                                    value={newAddress.addressLine1}
                                    onChange={(e) => setNewAddress({...newAddress, addressLine1: e.target.value})}
                                    required
                                    className="full-width"
                                />
                                <input
                                    type="text"
                                    placeholder="Address Line 2 (Optional)"
                                    value={newAddress.addressLine2}
                                    onChange={(e) => setNewAddress({...newAddress, addressLine2: e.target.value})}
                                    className="full-width"
                                />
                                <div className="form-row">
                                    <input
                                        type="text"
                                        placeholder="City"
                                        value={newAddress.city}
                                        onChange={(e) => setNewAddress({...newAddress, city: e.target.value})}
                                        required
                                    />
                                    <input
                                        type="text"
                                        placeholder="State"
                                        value={newAddress.state}
                                        onChange={(e) => setNewAddress({...newAddress, state: e.target.value})}
                                        required
                                    />
                                </div>
                                <label className="checkbox">
                                    <input
                                        type="checkbox"
                                        checked={newAddress.isDefault}
                                        onChange={(e) => setNewAddress({...newAddress, isDefault: e.target.checked})}
                                    />
                                    Set as default address
                                </label>
                                <button type="submit" className="btn-primary">Save Address</button>
                                <button 
                                    type="button" 
                                    className="btn-secondary"
                                    onClick={() => setShowAddressForm(false)}
                                >
                                    Cancel
                                </button>
                            </form>
                        )}

                        <div className="addresses-list">
                            {addresses.map((addr) => (
                                <div 
                                    key={getMongoId(addr)} 
                                    className={`address-card ${selectedAddress === getMongoId(addr) ? 'selected' : ''}`}
                                    onClick={() => setSelectedAddress(getMongoId(addr))}
                                >
                                    <input 
                                        type="radio" 
                                        name="address"
                                        checked={selectedAddress === getMongoId(addr)}
                                        onChange={() => setSelectedAddress(getMongoId(addr))}
                                    />
                                    <div className="address-details">
                                        <h4>{addr.fullName}</h4>
                                        <p>{addr.addressLine1}, {addr.addressLine2}</p>
                                        <p>{addr.city}, {addr.state} - {addr.zipCode}</p>
                                        <p className="mobile">{addr.mobile}</p>
                                        {addr.isDefault && <span className="badge-default">Default</span>}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Order Items Section */}
                    <div className="checkout-section">
                        <h2>2. Order Items</h2>
                        <div className="items-list">
                            {cart?.map((item) => (
                                <div key={item.productId} className="item-row">
                                    <div className="item-info">
                                        <h4>{item.productName}</h4>
                                        <p className="qty">Qty: {item.quantity}</p>
                                    </div>
                                    <div className="item-price">
                                        ₹{(item.price * item.quantity).toFixed(2)}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Payment Section */}
                    <div className="checkout-section">
                        <h2>3. Payment Method</h2>
                        <div className="payment-options">
                            <label className="payment-option">
                                <input type="radio" name="payment" defaultChecked />
                                <span>Razorpay (Credit/Debit Card, UPI, Wallet)</span>
                            </label>
                            <label className="payment-option">
                                <input type="radio" name="payment" />
                                <span>Cash on Delivery (COD)</span>
                            </label>
                            <label className="payment-option">
                                <input type="radio" name="payment" />
                                <span>Net Banking</span>
                            </label>
                        </div>
                    </div>
                </div>

                {/* Right Section - Price Summary */}
                <div className="checkout-right">
                    <div className="price-summary">
                        <h3>Price Details</h3>

                        <div className="summary-row">
                            <span>Subtotal ({cart?.length || 0} items)</span>
                            <span>₹{cartTotal.toFixed(2)}</span>
                        </div>

                        <div className="summary-row">
                            <span>Shipping Charge</span>
                            <span className={shipping === 0 ? 'free' : ''}>
                                {shipping === 0 ? 'FREE' : `₹${shipping.toFixed(2)}`}
                            </span>
                        </div>

                        <div className="summary-row">
                            <span>Tax (18%)</span>
                            <span>₹{tax.toFixed(2)}</span>
                        </div>

                        <div className="summary-divider"></div>

                        <div className="summary-row total">
                            <span>Total Amount</span>
                            <span>₹{grandTotal.toFixed(2)}</span>
                        </div>

                        {shipping === 0 && (
                            <p className="free-shipping-msg">✓ You get FREE Shipping</p>
                        )}

                        <button 
                            className="btn-place-order"
                            onClick={handlePlaceOrder}
                            disabled={!selectedAddress || !cart?.length}
                        >
                            Place Order
                        </button>

                        <button 
                            className="btn-back"
                            onClick={() => setCurrentPage('cart')}
                        >
                            Back to Cart
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default CheckoutPage;
